#include <stdio.h>

double calculate(double a, double b, char op) {
    switch (op) {
        case '+': return a + b;
        case '-': return a - b;
        case '*': return a * b;
        case '/':
            if (b == 0) {
                printf("Hata: Sifira bolme!\n");
                return 0;
            }
            return a / b;
        default:
            printf("Gecersiz islem: %c\n", op);
            return 0;
    }
}

int main() {
    double x = 15, y = 4;

    printf("x = %.0f, y = %.0f\n", x, y);
    printf("x + y = %.2f\n", calculate(x, y, '+'));
    printf("x - y = %.2f\n", calculate(x, y, '-'));
    printf("x * y = %.2f\n", calculate(x, y, '*'));
    printf("x / y = %.2f\n", calculate(x, y, '/'));

    printf("\nSifira bolme testi:\n");
    calculate(10, 0, '/');

    // Yuzde hesaplama
    double total = 250, discount = 15;
    double finalPrice = total - (total * discount / 100);
    printf("\n%.0f TL'nin %%%.0f indirimli hali: %.1f TL\n", total, discount, finalPrice);

    return 0;
}
